<?php
function my_plugin_display_custom_user_profile() {
    global $wpdb;

    if ( ! isset( $_GET['user_id'] ) || ! is_numeric( $_GET['user_id'] ) ) {
        return '<p>Please provide a valid user ID.</p>';
    }

    $user_id = intval( $_GET['user_id'] );

    $custom_user_table = $wpdb->prefix . 'custom_users';

    $user_data = $wpdb->get_row(
        $wpdb->prepare(
            "SELECT id, username, email, first_name, last_name, bio, membership_level, registration_date FROM {$custom_user_table} WHERE id = %d",
            $user_id
        )
    );

    $output = '';

    if ( $user_data ) {
        $output .= '<div class="custom-user-profile">';
        $output .= '<h2>Profile for ' . esc_html( $user_data->username ) . '</h2>';
        $output .= '<p><strong>User ID:</strong> ' . esc_html( $user_data->id ) . '</p>';
        $output .= '<p><strong>Username:</strong> ' . esc_html( $user_data->username ) . '</p>';
        $output .= '<p><strong>Email:</strong> ' . esc_html( $user_data->email ) . '</p>';
        $output .= '<p><strong>First Name:</strong> ' . esc_html( $user_data->first_name ) . '</p>';
        $output .= '<p><strong>Last Name:</strong> ' . esc_html( $user_data->last_name ) . '</p>';
        $output .= '<p><strong>Membership Level:</strong> ' . esc_html( $user_data->membership_level ) . '</p>';
        $output .= '<p><strong>Registration Date:</strong> ' . esc_html( $user_data->registration_date ) . '</p>';
        if ( ! empty( $user_data->bio ) ) {
            $output .= '<p><strong>Bio:</strong> ' . esc_html( $user_data->bio ) . '</p>';
        }
        $output .= '</div>';
    } else {
        $output .= '<p>User with ID ' . esc_html( $user_id ) . ' not found.</p>';
    }

    return $output;
}